INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Seated_Hamstring','Seated Hamstring','isquiotibiales',ARRAY['pantorrillas'],NULL,'stretching',ARRAY['In a seated position with your legs extended, have your partner stand behind you. Now, lean forward as your partner braces your shoulders with their hands. This will be your starting position.','Attempt to push your torso back for 10-20 seconds, as your partner prevents any actual movement of your torso.','Now relax your muscles as your partner increases the stretch by gently pushing your torso forward for 10-20 seconds.'],'In a seated position with your legs extended, have your partner stand behind you. Now, lean forward as your partner braces your shoulders with their hands. This will be your starting position. Attempt to push your torso back for 10-20 seconds, as your partner prevents any actual movement of your torso. Now relax your muscles as your partner increases the stretch by gently pushing your torso forward for 10-20 seconds.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Hamstring/0.jpg','exercisedb',true),('Seated_Hamstring_and_Calf_Stretch','Seated Hamstring and Calf Stretch','isquiotibiales',ARRAY['pantorrillas'],'otro','stretching',ARRAY['Loop a belt, rope, or band around one foot. Sit down with both legs extended . This will be your starting position.','Leaning forward slightly, pull on the belt to draw the toes of your foot back. Hold this position for 10-20 seconds and then repeat with the other leg.'],'Loop a belt, rope, or band around one foot. Sit down with both legs extended . This will be your starting position. Leaning forward slightly, pull on the belt to draw the toes of your foot back. Hold this position for 10-20 seconds and then repeat with the other leg.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Hamstring_and_Calf_Stretch/0.jpg','exercisedb',true),('Seated_Head_Harness_Neck_Resistance','Seated Head Harness Neck Resistance','cuello',ARRAY[]::text[],'otro','strength',ARRAY['Place a neck strap on the floor at the end of a flat bench. Once you have selected the weights, sit at the end of the flat bench with your feet wider than shoulder width apart from each other. Your toes should be pointed out.','Slowly move your torso forward until it is almost parallel with the floor. Using both hands, securely position the neck strap around your head. Tip: Make sure the weights are still lying on the floor to prevent any strain on the neck. Now grab the weight with both hands while elevating your torso back until it is almost perpendicular to the floor. Note: Your head and torso needs to be slightly tilted forward to perform this exercise.','Now place both hands on top of your knees. This is the starting position.','Slowly lower your neck down until your chin touches the upper part of your chest while breathing in.','While exhaling, bring your neck back to the starting position.','Repeat for the recommended amount of repetitions.'],'Place a neck strap on the floor at the end of a flat bench. Once you have selected the weights, sit at the end of the flat bench with your feet wider than shoulder width apart from each other. Your toes should be pointed out. Slowly move your torso forward until it is almost parallel with the floor. Using both hands, securely position the neck strap around your head. Tip: Make sure the weights are still lying on the floor to prevent any strain on the neck. Now grab the weight with both hands while elevating your torso back until it is almost perpendicular to the floor. Note: Your head and torso needs to be slightly tilted forward to perform this exercise. Now place both hands on top of your knees. This is the starting position. Slowly lower your neck down until your chin touches the upper part of your chest while breathing in. While exhaling, bring your neck back to the starting position. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Head_Harness_Neck_Resistance/0.jpg','exercisedb',true),('Seated_Leg_Curl','Seated Leg Curl','isquiotibiales',ARRAY[]::text[],'máquina','strength',ARRAY['Adjust the machine lever to fit your height and sit on the machine with your back against the back support pad.','Place the back of lower leg on top of padded lever (just a few inches under the calves) and secure the lap pad against your thighs, just above the knees. Then grasp the side handles on the machine as you point your toes straight (or you can also use any of the other two stances) and ensure that the legs are fully straight right in front of you. This will be your starting position.','As you exhale, pull the machine lever as far as possible to the back of your thighs by flexing at the knees. Keep your torso stationary at all times. Hold the contracted position for a second.','Slowly return to the starting position as you breathe in.','Repeat for the recommended amount of repetitions.'],'Adjust the machine lever to fit your height and sit on the machine with your back against the back support pad. Place the back of lower leg on top of padded lever (just a few inches under the calves) and secure the lap pad against your thighs, just above the knees. Then grasp the side handles on the machine as you point your toes straight (or you can also use any of the other two stances) and ensure that the legs are fully straight right in front of you. This will be your starting position. As you exhale, pull the machine lever as far as possible to the back of your thighs by flexing at the knees. Keep your torso stationary at all times. Hold the contracted position for a second. Slowly return to the starting position as you breathe in. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Leg_Curl/0.jpg','exercisedb',true),('Seated_Leg_Tucks','Seated Leg Tucks','abdominales',ARRAY[]::text[],'peso corporal','strength',ARRAY['Sit on a bench with the legs stretched out in front of you slightly below parallel and your arms holding on to the sides of the bench. Your torso should be leaning backwards around a 45-degree angle from the bench. This will be your starting position.','Bring the knees in toward you as you move your torso closer to them at the same time. Breathe out as you perform this movement.','After a second pause, go back to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'],'Sit on a bench with the legs stretched out in front of you slightly below parallel and your arms holding on to the sides of the bench. Your torso should be leaning backwards around a 45-degree angle from the bench. This will be your starting position. Bring the knees in toward you as you move your torso closer to them at the same time. Breathe out as you perform this movement. After a second pause, go back to the starting position as you inhale. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Leg_Tucks/0.jpg','exercisedb',true),('Seated_One-Arm_Dumbbell_Palms-Down_Wrist_Curl','Seated One-Arm Dumbbell Palms-Down Wrist Curl','antebrazos',ARRAY[]::text[],'mancuernas','strength',ARRAY['Sit on a flat bench with a dumbbell in your right hand.','Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.','Lean forward and place your right forearm on top of your upper right thigh with your palm down. Tip: Make sure that the back of the wrist lies on top of your knees. This will be your starting position.','Lower the dumbbell as far as possible as you keep a tight grip on the dumbbell. Inhale as you perform this movement.','Now curl the dumbbell as high as possible as you contract the forearms and as you exhale. Keep the contraction for a second before you lower again. Tip: The only movement should happen at the wrist.','Perform for the recommended amount of repetitions, switch arms and repeat the movement.'],'Sit on a flat bench with a dumbbell in your right hand. Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart. Lean forward and place your right forearm on top of your upper right thigh with your palm down. Tip: Make sure that the back of the wrist lies on top of your knees. This will be your starting position. Lower the dumbbell as far as possible as you keep a tight grip on the dumbbell. Inhale as you perform this movement. Now curl the dumbbell as high as possible as you contract the forearms and as you exhale. Keep the contraction for a second before you lower again. Tip: The only movement should happen at the wrist. Perform for the recommended amount of repetitions, switch arms and repeat the movement.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_One-Arm_Dumbbell_Palms-Down_Wrist_Curl/0.jpg','exercisedb',true),('Seated_One-Arm_Dumbbell_Palms-Up_Wrist_Curl','Seated One-Arm Dumbbell Palms-Up Wrist Curl','antebrazos',ARRAY[]::text[],'mancuernas','strength',ARRAY['Sit on a flat bench with a dumbbell in your right hand.','Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.','Lean forward and place your right forearm on top of your upper right thigh with your palm up. Tip: Make sure that the front of the wrist lies on top of your knees. This will be your starting position.','Lower the dumbbell as far as possible as you keep a tight grip on the dumbbell. Inhale as you perform this movement.','Now curl the dumbbell as high as possible as you contract the forearms and as you exhale. Keep the contraction for a second before you lower again. Tip: The only movement should happen at the wrist.','Perform for the recommended amount of repetitions, switch arms and repeat the movement.'],'Sit on a flat bench with a dumbbell in your right hand. Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart. Lean forward and place your right forearm on top of your upper right thigh with your palm up. Tip: Make sure that the front of the wrist lies on top of your knees. This will be your starting position. Lower the dumbbell as far as possible as you keep a tight grip on the dumbbell. Inhale as you perform this movement. Now curl the dumbbell as high as possible as you contract the forearms and as you exhale. Keep the contraction for a second before you lower again. Tip: The only movement should happen at the wrist. Perform for the recommended amount of repetitions, switch arms and repeat the movement.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_One-Arm_Dumbbell_Palms-Up_Wrist_Curl/0.jpg','exercisedb',true),('Seated_One-arm_Cable_Pulley_Rows','Seated One-arm Cable Pulley Rows','espalda media',ARRAY['bíceps','dorsales','trapecios'],'cable','strength',ARRAY['To get into the starting position, first sit down on the machine and place your feet on the front platform or crossbar provided making sure that your knees are slightly bent and not locked.','Lean over as you keep the natural alignment of your back and grab the single handle attachment with your left arm using a palms-down grip.','With your arm extended pull back until your torso is at a 90-degree angle from your legs. Your back should be slightly arched and your chest should be sticking out. You should be feeling a nice stretch on your lat as you hold the bar in front of you. The right arm can be kept by the waist. This is the starting position of the exercise.','Keeping the torso stationary, pull the handles back towards your torso while keeping the arms close to it as you rotate the wrist, so that by the time your hand is by your abdominals it is in a neutral position (palms facing the torso). Breathe out as you perform that movement. At that point you should be squeezing your back muscles hard.','Hold that contraction for a second and slowly go back to the original position while breathing in. Tip: Remember to rotate the wrist as you go back to the starting position so that the palms are facing down again.','Repeat for the recommended amount of repetitions and then perform the same movement with the right hand.'],'To get into the starting position, first sit down on the machine and place your feet on the front platform or crossbar provided making sure that your knees are slightly bent and not locked. Lean over as you keep the natural alignment of your back and grab the single handle attachment with your left arm using a palms-down grip. With your arm extended pull back until your torso is at a 90-degree angle from your legs. Your back should be slightly arched and your chest should be sticking out. You should be feeling a nice stretch on your lat as you hold the bar in front of you. The right arm can be kept by the waist. This is the starting position of the exercise. Keeping the torso stationary, pull the handles back towards your torso while keeping the arms close to it as you rotate the wrist, so that by the time your hand is by your abdominals it is in a neutral position (palms facing the torso). Breathe out as you perform that movement. At that point you should be squeezing your back muscles hard. Hold that contraction for a second and slowly go back to the original position while breathing in. Tip: Remember to rotate the wrist as you go back to the starting position so that the palms are facing down again. Repeat for the recommended amount of repetitions and then perform the same movement with the right hand.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_One-arm_Cable_Pulley_Rows/0.jpg','exercisedb',true),('Seated_Overhead_Stretch','Seated Overhead Stretch','abdominales',ARRAY[]::text[],NULL,'stretching',ARRAY['Sit up straight on an exercise mat.','Touch the soles of your feet together with your feet six to eight inches in front of your hips.','Place one hand on the floor beside you and your other hand behind your head.','Lift your elbow to the ceiling as you incline your torso to the other side. Hold for 10 to 20 seconds, then switch sides.'],'Sit up straight on an exercise mat. Touch the soles of your feet together with your feet six to eight inches in front of your hips. Place one hand on the floor beside you and your other hand behind your head. Lift your elbow to the ceiling as you incline your torso to the other side. Hold for 10 to 20 seconds, then switch sides.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Overhead_Stretch/0.jpg','exercisedb',true),('Seated_Palm-Up_Barbell_Wrist_Curl','Seated Palm-Up Barbell Wrist Curl','antebrazos',ARRAY[]::text[],'barra','strength',ARRAY['Hold a barbell with both hands and your palms facing up; hands spaced about shoulder width.','Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.','Lean forward and place your forearms on top of your upper thighs with your palms up. Tip: Make sure that the front of the wrists lay on top of your knees. This will be your starting position.','Lower the bar as far as possible while inhaling and keeping a tight grip.','Now curl bar up as high as possible while flexing the forearms and exhaling. Hold the contraction at the top for a second and Tip: Only the wrist should move.'],'Hold a barbell with both hands and your palms facing up; hands spaced about shoulder width. Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart. Lean forward and place your forearms on top of your upper thighs with your palms up. Tip: Make sure that the front of the wrists lay on top of your knees. This will be your starting position. Lower the bar as far as possible while inhaling and keeping a tight grip. Now curl bar up as high as possible while flexing the forearms and exhaling. Hold the contraction at the top for a second and Tip: Only the wrist should move.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Palm-Up_Barbell_Wrist_Curl/0.jpg','exercisedb',true);